<?php

namespace VSHM\Settings;

use VSHM\UI\Customizer\Radios_Control;

defined('ABSPATH') || exit;

/**
 *  Class SettingMapsStyle
 */
class SettingMapsStyle extends SettingCustomizer
{
    public const ID = 'googleMapsStyle';

    public static function customize_register($wp_customize, string $plugin_slug): void
    {
        parent::customize_register($wp_customize, $plugin_slug);

        if ($plugin_slug === vshm()->plugin['SLUG']) {
            $wp_customize->add_control(new Radios_Control($wp_customize, static::get_option_id(), [
                'label'       => static::getLabel(),
                'section'     => static::getSection(),
                'description' => static::getDescription(),
                'priority'    => 120,
                'type'        => 'vshm-radios-grid-2',
                'input_attrs' => [
                    0  => 'height: 70px;background-image: url("data:image/png;base64,");',
                    1  => 'height: 70px;background-image: url("data:image/png;base64,");',
                    2  => 'height: 70px;background-image: url("data:image/png;base64,");',
                    3  => 'height: 70px;background-image: url("data:image/png;base64,");',
                    4  => 'height: 70px;background-image: url("data:image/png;base64,");',
                    5  => 'height: 70px;background-image: url("data:image/png;base64,");',
                    6  => 'height: 70px;background-image: url("data:image/png;base64,");',
                    7  => 'height: 70px;background-image: url("data:image/png;base64,");',
                    8  => 'height: 70px;background-image: url("data:image/png;base64,");',
                    9  => 'height: 70px;background-image: url("data:image/png;base64,");',
                    10 => 'height: 70px;background-image: url("data:image/png;base64,");',
                    11 => 'height: 70px;background-image: url("data:image/png;base64,");',
                    12 => 'height: 70px;background-image: url("data:image/png;base64,");',
                ],
                'choices'     => [
                    0  => __('Default style', 'team-booking'),
                    1  => 'Light Gray (by ColorByt)',
                    2  => 'Unsaturated Browns (by Simon Goellner)',
                    3  => 'Pale Dawn (by Adam Krogh)',
                    4  => 'Orange (by bjorn)',
                    5  => 'Coy Beauty (by Danika Pariseau)',
                    6  => 'MapBox (by Sam Herbert)',
                    7  => 'Shades of Grey (by Adam Krogh)',
                    8  => 'Subtle Grayscale (by Paulo Avila)',
                    9  => 'Bluish (by Stefan)',
                    10 => 'even lighter (by anda)',
                    11 => 'Two Tone (by Arvin)',
                    12 => 'buhler (by Colin Zwicker)',
                ]
            ]));
        }
    }

    public static function getLabel(): string
    {
        return __('Google Maps Style', 'team-booking');
    }

    public static function getDescription(): string
    {
        return __('Do you want more styles or even create your own style? Just set this to "Default style", then install the SnazzyMaps WordPress plugin.', 'team-booking');
    }

    /**
     * @return string
     */
    public static function getSection(): string
    {
        return vshm()->plugin['SLUG'] . '-maps';
    }

    /**
     * @var string
     */
    public static $sanitizeCallback = '';

    public static function sanitize($value): int
    {
        return ((int)$value < 13 && (int)$value >= 0) ? (int)$value : static::default();
    }

    public static function default(): int
    {
        return 0;
    }
}
